// Solution
// -----------------------------------------------

struct Solver {
    N: usize,
    dp: Vec<Vec<i64>>,
}

impl Solver {
    fn dfs(&mut self, x: usize, y: usize) -> i64 {
        if self.dp[x][y] == 0 {
            self.dp[x][y] = self.do_dfs(x, y);
        }
        self.dp[x][y]
    }

    fn do_dfs(&mut self, x: usize, y: usize) -> i64 {
        assert!(x < y);
        if y - x == 1 {
            return 0;
        }

        let mut min_w = std::i64::MAX;
        for z in x + 1..y {
            min_w = min(min_w, self.dfs(x, z) + self.dfs(z, y) + (x * y * z) as i64)
        }
        min_w
    }
}

fn main() {
    std::thread::Builder::new()
        .stack_size(200 * 1024 * 1024)
        .spawn(|| {
            let N = read!(usize);
            let w = Solver {
                N: N,
                dp: vec![vec![0; N + 2]; N + 2],
            }
            .dfs(1, N);
            println!("{}", w)
        })
        .unwrap()
        .join()
        .unwrap();
}
